6	const KNOWN_ITEM_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
7	
8	function validateItems(items: Step[]): void {
9	  for (const item of items) {
10	    if (!KNOWN_ITEM_TYPES.includes(item.type)) {
11	      throw new Error(`Unknown item type: ${item.type}`);
12	    }
13	  }
14	}
