21	function validateDamageEntries(damages: Step[]): void {
22	  for (const damage of damages) {
23	    if (damage.amount < 0) {
24	      throw new Error(`Damage amount cannot be negative: ${damage.amount}`);
25	    }
26	  }
27	}
