29	function validateDamagesAgainstPolicy(damages: Step[], policyItems: Step[]): void {
30	  const policyItemTypes = policyItems.map((i: any) => i.type);
31	  for (const damage of damages) {
32	    if (!policyItemTypes.includes(damage.itemType)) {
33	      throw new Error(`Damage references item not in policy: ${damage.itemType}`);
34	    }
35	  }
36	  const policyCounts: Record<string, number> = {};
37	  for (const item of policyItems) {
38	    policyCounts[item.type] = (policyCounts[item.type] || 0) + 1;
39	  }
40	  const damageCounts: Record<string, number> = {};
41	  for (const damage of damages) {
42	    damageCounts[damage.itemType] = (damageCounts[damage.itemType] || 0) + 1;
43	  }
44	  for (const type of Object.keys(damageCounts)) {
45	    if (damageCounts[type] > (policyCounts[type] || 0)) {
46	      throw new Error(`More damages of type ${type} than insured`);
47	    }
48	  }
49	}
