51	function executeClaim(step: Step, steps: Step[]): any {
52	  const referencedQuote = steps[step.policy];
53	  validateDamageEntries(step.incident.damages);
54	  validateDamagesAgainstPolicy(step.incident.damages, referencedQuote.items);
55	  return claim({ policy: { items: referencedQuote.items }, incident: step.incident });
